import{a as e,i as t,r as n,t as r}from"./app-DJF5ueEI.js";var i=JSON.parse(`{"path":"/blogs/shopify-magento2-integration.html","title":"Guide for Adobe Commerce Shopify Connector","lang":"en-US","frontmatter":{},"git":{"updatedTime":1781706203000,"contributors":[{"name":"Mohd Munassir Alam","username":"","email":"munassir.alam632@webkul.in","commits":2},{"name":"Cursor","username":"Cursor","email":"cursoragent@cursor.com","commits":1,"url":"https://github.com/Cursor"}],"changelog":[{"hash":"fec0b4ca4a2ac9add31ec0545055b0e7503c7108","time":1781706203000,"email":"munassir.alam632@webkul.in","author":"Mohd Munassir Alam","message":"Updated Blog MD files"},{"hash":"4a53557ca9c67c38b21dbd5c17281350dcba1744","time":1781697054000,"email":"munassir.alam632@webkul.in","author":"Mohd Munassir Alam","message":"Add Shopify Magento 2 integration user guide.","coAuthors":[{"name":"Cursor","email":"cursoragent@cursor.com"}]}]},"filePathRelative":"blogs/shopify-magento2-integration.md"}`),a={name:`shopify-magento2-integration.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="guide-for-adobe-commerce-shopify-connector" tabindex="-1"><a class="header-anchor" href="#guide-for-adobe-commerce-shopify-connector"><span>Guide for Adobe Commerce Shopify Connector</span></a></h1><p>Updated 9 June 2026</p><p><a href="https://multi-shopify-store-mage-connect-demo.magento2.webkul.in/demomanagement/viewdemo/index/demoid/1/" target="_blank" rel="noopener noreferrer">Live Demo</a></p><p><a href="https://store.webkul.com/magento2-shopify-connector.html" target="_blank" rel="noopener noreferrer">Magento 2 Shopify Connecto</a><a href="https://store.webkul.com/magento2-shopify-connector.html" target="_blank" rel="noopener noreferrer">r</a> – Every E-commerce merchant wants to expose the product range to more and more potential customers via multi-channel selling to grow their business.</p><p>However, if you are a multi-channel seller on Magento 2 and Shopify store then managing both the stores could be a tedious task.</p><p>By using the <strong>Magento 2 (Adobe Commerce) Shopify Connector</strong>\xA0module, the admin can integrate the Magento store with the Shopify store.</p><p>Further, the admin will no longer require to configure the product data and information on both the stores separately.</p><p>The admin can sync the product, and orders from Shopify to the Magento store. And, can even export the products from the Magento store to Shopify.</p><p>Moreover, the admin can synchronize the products and orders from the multiple Shopify accounts using the module.</p><p>Check a brief overview of the plugin configuration setting options –</p><p>-6vVHN0qeJs</p><h2 id="features" tabindex="-1"><a class="header-anchor" href="#features"><span><strong>Features</strong></span></a></h2><ul><li>The admin can map Shopify categories with Magento 2 categories.</li><li>Admin can import Shopify products to Magento 2 store.</li><li>The admin can set the price rules for the imported/exported products.</li><li>Admin can set a default category for the imported products in the Magento 2 store.</li><li>The admin can set the default quantity for exported products in the Magento 2 store.</li><li>The admin can import Simple as well as Configurable(product with variants) product types.</li><li>The product information like base image, additional images, name, price, SKU, description, quantity, weight, and super attributes with options get import along with the product.</li><li>Order status and tracking number get updated to Shopify from Magento 2 when the order is processed from Magento 2.</li><li>The admin can export Magento 2 store products to the Shopify store.</li><li>The admin can export Simple as well as Configurable product types.</li><li>Imported Shopify product works like same as Magento product.</li><li>The admin can import Shopify orders to Magento 2 store.</li><li>Admin can set the default store view for the imported order in the Magento 2 store.</li><li>The admin can add multiple Shopify Accounts.</li><li>The admin can view and manage the Shopify Accounts.</li><li>The orders will fetch automatically via Cron and if order items do not exist in Magento, they will automatically be created.</li><li>Quantity management on Shopify for the orders placed at the Magento store.</li><li>Product export to Shopify with the listing template.</li><li>Shopify connector module also works with a multi-store Magento setup.</li><li>Send product information according to locales such as – en, es, de.</li><li>Export product and product model through product only export(CSV)</li><li>Works with simple, configurable, and virtual products.</li><li>Support multi-language translations.</li></ul><h2 id="installation" tabindex="-1"><a class="header-anchor" href="#installation"><span><strong>Installation</strong></span></a></h2><p>In the mean time, check other quality <a href="https://store.webkul.com/Magento-2.html" target="_blank" rel="noopener noreferrer">Magento 2 extension </a>that are easy to install.</p><p>Customers will get a\xA0<strong>zip folder</strong> and they have to extract the contents of this zip folder on their system.</p><p>Extracted folder has an <strong>src</strong>\xA0folder, inside the src folder you have the\xA0<strong>app</strong>\xA0folder.</p><p>You need to transfer this\xA0<strong>app</strong>\xA0folder\xA0into the Magento2 root directory on the server as shown below.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2017/07/1-9-e1634634198330.png" target="_blank" rel="noopener noreferrer"><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2017/07/1-9-e1634634198330.png" alt="INSTALLATION"></a></p><p>After the successful installation, you have to run these commands in the\xA0Magento2 root directory.</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">php bin/magento setup:upgrade</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">php bin/magento setup:di:compile</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">php bin/magento setup:static-content:deploy</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">php bin/magento indexer:reindex</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">php bin/magento cache:flush</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>For Multilingual support, please navigate to\xA0<strong>Store&gt;Configuration&gt;General &gt;Locale Options</strong>. And select your desire language from the **Locale\xA0**option.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-locale.webp" alt="locale"></p><h2 id="language-translation" tabindex="-1"><a class="header-anchor" href="#language-translation"><span><strong>Language Translation</strong></span></a></h2><p>For module translation, navigate to the following path in your system <strong>app/code/Webkul/MultiShopifyStoreMageConnect/i18n/en_US.csv.</strong></p><p>Open the file named\xA0**en_US.CSV\xA0**for editing as shown in the below screenshot.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2017/07/22-3.png" target="_blank" rel="noopener noreferrer"><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2017/07/22-3.png" alt="LANGUAGE TRANSLATION"></a></p><p>Then replace the words after the\xA0**comma(,)\xA0**on the right in the file with your translated words.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/csv.png" alt="Shopify Magento 2 csv"></p><p>After editing and translating the CSV file, you need to save the translated file name according to your region language and country code such as –<strong>de_DE.CSV</strong>.</p><p>Follows by uploading the translated file to the same folder from where you have obtained it. Now your module translation is complete.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2017/07/2016-05-02_16-25-34-3.png" target="_blank" rel="noopener noreferrer"><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2017/07/2016-05-02_16-25-34-3.png" alt="Shopify Magento 2 Language translation"></a></p><h2 id="how-to-get-api-credential-from-your-shopify-account" tabindex="-1"><a class="header-anchor" href="#how-to-get-api-credential-from-your-shopify-account"><span>How to Get API Credential From Your Shopify Account</span></a></h2><p>To get the API credentials the admin needs to generate the Shopify API credential first using the Shopify account.</p><p>The admin can visit the Shopify store for which the admin wants to connect and sync the WooCommerce store.</p><h3 id="step-1-–-log-in-to-your-shopify-admin" tabindex="-1"><a class="header-anchor" href="#step-1-–-log-in-to-your-shopify-admin"><span><strong>Step 1 – Log in to your Shopify Admin</strong></span></a></h3><p>First, log in to your Shopify store using:</p><p>Your store URL</p><p>Your admin username and password</p><p>Make sure you are logged in as a store owner or have app developer permissions.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/login-page-1200x675-5.webp" alt="login-page-1200x675"></p><h3 id="step-2-–-navigate-to-apps" tabindex="-1"><a class="header-anchor" href="#step-2-–-navigate-to-apps"><span><strong>Step 2 – Navigate to “Apps ”</strong></span></a></h3><p>From the Shopify left sidebar menu:</p><p>Click Settings, then select Apps</p><p>This is where all integrations and custom apps are manage</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/shopify-connector-deleloper-dashboard-1.webp" alt="shopify-connector-deleloper-dashboard"></p><p><strong>Step 3 – Open the “Develop Apps” Section</strong></p><p>On the top-right corner of the Apps page, click:</p><p>Develop apps</p><p>This option allows you to create custom/private apps for API integrations.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/shopify-connector-deleloper-dashboard-1200x559-2.webp" alt="shopify-connector-deleloper-dashboard-1200x559"></p><p><strong>Step 4 – Click on the “Build apps in the developer dashboard” option.</strong></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/shopify-develop-apps-button-screen-2.webp" alt="shopify-develop-apps-button-screen"></p><p>The dev dashboard opens as shown in the image below</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/app-development-screen-1200x559-2.webp" alt="app-development-screen-1200x559"></p><p>**Step 5 – Create a New App<br> **</p><p>Next, click the button “Create app”</p><p>This will open the app creation pop-up.</p><p>Fill in the app name – Any name of your choice (In my case, I choose, “Webkul App”)</p><p>Then click Create</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/shopify-app-name-and-developer-email-form-1200x559-2.webp" alt="shopify-app-name-and-developer-email-form-1200x559"></p><p>Now the App Integration and Configuration dashboard opens, where you can assign</p><p>the required permissions to your app as shown in the image below.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/shopify-app-connection-page.webp" alt="shopify-app-configuration-admin-api-integration"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/shopify-image.webp" alt="shopify-image"></p><p><strong>Step 6 – Configure Admin API Scopes</strong></p><p>Fill the following details</p><p><strong>App URL</strong> –</p><p>https://your-magento-store.com/</p><p><strong>Redirect URL</strong> –</p><p>https://your-magento-store.com/multishopifystoremageconnect/oauth/callback</p><p>This is the URL where your app is hosted or where Shopify should send\xA0users after installing or opening the app.</p><p>Now you need to assign permissions to your app.</p><p>Then go to the Access section</p><p>From here, select the required API scopes/permissions (for example: Products,</p><p>Orders, Inventory, Customers etc.), depending on your module requirements.</p><p>Also, it should have\xA0Read and Write\xA0API permission for the following:</p><ul><li>Customer details and customer groups; inventory; orders, transactions, and fulfillment.</li><li>Product information including products, variants, and collections.</li><li>Locations</li><li>Shipping rates</li><li>Discounts</li><li>Online Store Pages access via the GraphQL API.</li></ul><p>Note:\xA0<strong>While making the Webhook Subscription, please make sure to select the latest</strong></p><p><strong>Event Version</strong>.</p><p>After selecting the scopes and Event version, click\xA0<strong>Release.</strong></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/shopify-admin-api-access-scopes-selection-1200x559-3.webp" alt="shopify-admin-api-access-scopes-selection-1200x559"></p><p>After successfully selecting all the required permissions, click the Release button</p><p>again. A new version of the app will be created as shown in the image below.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/new-app-version.webp" alt="new-app-version"></p><h3 id="step-7-–-retrieve-your-api-credentials" tabindex="-1"><a class="header-anchor" href="#step-7-–-retrieve-your-api-credentials"><span><strong>Step 7 – Retrieve Your API Credentials</strong></span></a></h3><p>After that, go to the\xA0<strong>API Credentials</strong>\xA0section in the app settings, where you can view</p><p>your generated keys.</p><p>You will be able to see:</p><ul><li>Client ID (API Key)</li><li>Client Secret Key</li></ul><p>Click\xA0<strong>Reveal</strong>\xA0to display the secret key.</p><p>Copy both values carefully and keep them stored in a secure location.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/shopify-reveal-client-secret-key-screen-1200x559-2.webp" alt="shopify-reveal-client-secret-key-screen-1200x559"></p><p>**Step 8 – Install the App<br> **</p><p>Once scopes are configured, install the app to activate API access.</p><p>Click on Install app and confirm the installation in the pop-up.</p><p>This generates your OAuth application credentials.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/shopify-install-app-button-screen-1200x559-2.webp" alt="shopify-install-app-button-screen-1200x559"></p><h2 id="how-to-get-webhook-verification-key-in-add-shopify-account-option" tabindex="-1"><a class="header-anchor" href="#how-to-get-webhook-verification-key-in-add-shopify-account-option"><span>How to Get Webhook Verification key in Add Shopify Account option?</span></a></h2><p>In Shopify, a webhook is a way to automatically send data to an external URL when certain events happen in your store.</p><p><strong>Steps to create/view webhook key:</strong></p><p>Log in to your Shopify admin panel an navigate to the Webhooks section.</p><p>Click on “Settings” at the bottom of the left-hand menu.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/tap-settings.webp" alt="shopify settings option"><br> Select “Notifications” from the Settings menu.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/notifications.webp" alt="notifications"><br> Scroll down to the “Webhooks” section.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/web-hooks.webp" alt="webhooks section button"></p><p>Click the “Create webhook” button.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/create-webhooks.webp" alt="
create webhook"><br> In the “Event” dropdown, select the event you want to trigger the webhook (e.g., “Order creation”).</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webhook-popup.webp" alt="webhook popup"><br> The “Format” dropdown, choose the format in which the data will be sent (JSON or XML).</p><p>In the “URL” field, enter the URL of the endpoint where you want to receive the webhook data.</p><p>After filling in the details, click “Save webhook”.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webhook-key.webp" alt="webhook verification key "></p><h2 id="module-configuration" tabindex="-1"><a class="header-anchor" href="#module-configuration"><span><strong>Module Configuration</strong></span></a></h2><p>After the module installation, the admin will configure the module settings by navigating to the given path.</p><p><strong>Stores &gt; Configuration &gt; Webkul &gt; Shopify Connect</strong>\xA0as per the below image.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento-2-shopify-connector-general-settings.webp" alt="general settings"></p><p>Here the admin will:</p><ul><li>Update Product Qty-\xA0Set\xA0“Yes” to allow updating the product quantity on the Shopify store if the order for the product is placed on the Magento store. Else set\xA0“No” to don’t allow updating the product quantity on the Shopify store if the order for the product is placed on the Magento store.</li><li>Update Product –\xA0Set\xA0“Yes” to allow product updates on the Shopify store if the product is updated on the Magento store. Else set\xA0“No” to don’t allow product updates on the Shopify store if the product gets an update on the Magento store.</li><li>Use Lastname As Firstname In Order – Set “Yes” to use the Lastname of the customer as the Firstname in Magento 2 for order import. Else, Set “No” to enable the Custom Firstname option.</li><li>Custom Firstname –\xA0 Input a custom Firstname of the customer in the order.</li><li>Location ID for Fulfillment – Here, the admin need to enter the location id of the Shopify store.</li></ul><p>The admin can also navigate to the Configuration by navigating from the sidepanel, they have to follow the following path <strong>Webkul Shopify Connector&gt;Configuration.</strong></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-sidepanel-5.webp" alt="webkul-magento2-shopify-connector-sidepanel"></p><p>To get the Shopify store location, log in to your Shopify account and navigate to the location section.</p><p>Tap the location that you want to use and after that, in the URL you will find the Location Id as per the snapshot below.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/screenshot_from_2023_07_06_11_46_02.png" alt="screenshot_from_2023_07_06_11_46_02"></p><ul><li>Shopify Vendor name – Here, enter the Shopify store vendor name as per your Shopify store account name.</li></ul><h2 id="general-settings" tabindex="-1"><a class="header-anchor" href="#general-settings"><span>General Settings:\xA0</span></a></h2><ul><li>Product Auto Export to Shopify – Here, if this option is enabled then when you create the products in Magento they will automatically be exported to Shopify as required.</li><li>Default Shopify Store – Select the store from the drop-down option so when you create a product that will automatically be exported to the selected Shopify store.</li><li>Product Auto Delete – Choose Yes to auto delete product at Shopify when you delete at Magento 2 end.</li></ul><p>After completing module settings, then the admin will have a **Webkul Shopify Connector **menu option as per the below image.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-sidepanel-4.webp" alt="webkul-magento2-shopify-connector-sidepanel"></p><p>Here, the admin will have several sub-menu options to manage the <strong>Magento 2 Shopify Connector</strong> which we will discuss one by one in detail.</p><ul><li>Shopify Accounts</li><li>Templates</li><li>Category Mapping</li><li>Price Rule</li><li>Configuration</li></ul><h2 id="shopify-accounts" tabindex="-1"><a class="header-anchor" href="#shopify-accounts"><span><strong>Shopify Accounts</strong></span></a></h2><p>Now, the admin can add Shopify account credentials. The admin can navigate to **Webkul Shopify Connector &gt; Shopify Accounts **for managing and adding Shopify Accounts.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-sidepanel-8.webp" alt="sidepanel3"></p><p>After clicking on <strong>Shopify Account Connect</strong>, the following page will open showing Shopify accounts list with the ** Store Name** and <strong>Shopify User Id.</strong></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-add-account-1.webp" alt="add account"></p><p>Here, the admin can:</p><ul><li>Edit –\xA0edit the Shopify account details by clicking on this link.</li><li>Delete\xA0– remove the existing Shopify account from the list using the action drop-down list.</li><li>Add Shopify Account –\xA0add/create a new Shopify account.</li></ul><p>After clicking on <strong>“****Add Shopify Account”</strong>, the admin will navigate to the New Shopify Account page as per the below image.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/connect-shopify-account.webp" alt="connect-shopify-account"></p><p>Here, the admin will enter :</p><ul><li>Store Name:\xA0Enter your Shopify store name and this will not get change once get save in the Magento 2 store.</li><li>Attribute set:\xA0Select the attribute set for the imported product.</li><li>Client ID: Enter the Client ID that the admin has received while creating the app from the Shopify account.</li><li>Client Secret:\xA0Enter the Client Secret that the admin has received while creating the app from the Shopify account.</li><li>Webhook Verification Key – In Shopify, a webhook is a way to automatically send data to an external URL when certain events happen in your store. Check how to get the <a href="https://webkul.com/blog/shopify-magento2-integration/#how-to-get-webhook-verification-key-in-add-shopify-account-option" target="_blank" rel="noopener noreferrer">Webhook verification key</a>.</li><li>Domain Name:\xA0Enter the base URL of your\xA0Shopify store like – your store name.myshopify.comFor example – webkul.myshopify.com</li></ul><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/store-name.png" target="_blank" rel="noopener noreferrer"><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/store-name.png" alt="domain name"></a></p><p>When the admin clicks on the **“****Save Shopify Account”\xA0**button, the following options become visible as per the below image.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/generatetoken-1.webp" alt="generatetoken"></p><p>After entering the required details, the admin needs to click the <strong>“Generate Access Token”</strong> button to start the Shopify authentication process.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/shopifyconnected-1.webp" alt="shopifyconnected"></p><p>Once authentication is successfully completed, the system connects the Shopify store with Magento 2.</p><p>The system then displays the <strong>“Shopify Authorized”</strong> status below the Domain Name field, confirming that the Shopify account is connected.</p><p><strong>Note:</strong> After the Shopify Connect account details are saved, the general configuration and listing configuration also need to be saved again for the further process.</p><h3 id="general-configuration" tabindex="-1"><a class="header-anchor" href="#general-configuration"><span><strong>General Configuration:</strong></span></a></h3><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-general-configuration-1.webp" alt="webkul-magento2-shopify-connector-general-configuration"></p><p>Here admin will configure the\xA0<strong>“General Configuration”.</strong></p><ul><li>Revise Shopify Product:\xA0Select ‘Yes’ to revise Shopify item automatically when an item update on the Magento 2 store else select the ‘No’ option.</li><li>Default Category:\xA0Select the default category of Magento 2 store for assigning to Shopify products while product import.</li><li>Default Store View – Select the default store view of the Magento 2 for order syncing.</li><li>Import Product:\xA0Select “All Products” if want to import all the products. Else select “Only Mapped Categories Product’s” if want to import only those products whose Shopify store categories have been mapped with Magento 2 Store.</li><li>Product Description with HTML: Set “Yes” if want to show the product description in HTML format while import and export. Else set “No” if want to show the product description in plain text format.</li><li>Price Rule Applicable For:\xA0Choose to apply price rule on import product, export product or go with none option to remain the price rule unapplied.</li><li>Order Status: Set default order status for the orders which are import from the Shopify store.</li><li>Conversion Rate: Set the conversion rate.</li></ul><h3 id="listing-configuration" tabindex="-1"><a class="header-anchor" href="#listing-configuration"><span>Listing Configuration:</span></a></h3><p>Under this section, the admin will configure the listing settings.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-listing-configuration-1.webp" alt="listing configuration"></p><p>Here, the admin will:</p><ul><li>Default Product Quantity – Set default product quantity for a product that gets export to Shopify if product quantity is zero on the Magento 2 store.</li><li>Select Template – The admin can select the template. As per the chosen template, the additional information will get export along with the product.</li><li>Product Type for Export-\xA0Select the product type which the admin wants to export.</li><li>Other Information – Write any information for export products.</li></ul><h3 id="category-mapping" tabindex="-1"><a class="header-anchor" href="#category-mapping"><span>Category Mapping:</span></a></h3><p>After this, the admin will map the Magento 2 store categories with the Shopify store categories by clicking on the\xA0<strong>Category Mapping</strong> tab.</p><p>This will navigate the admin to a new page as per the below image.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-map-category-1.webp" alt="map-category"></p><p>For mapping, select the Magento Store Category which the admin wants to map with the Shopify store Category.</p><p><strong>Note:</strong></p><ul><li>Only one category will map at a time.</li><li>You cannot map the parent categories.</li><li>You need to select the sub-category for mapping.</li></ul><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-leaf-category-mapping-1.webp" alt="leaf-category-mapping"></p><p>For successful category mapping, hit the\xA0**Save\xA0****Mapping\xA0**button. Then, a pop-up window will get a display in which the admin will click the **Ok\xA0**button.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-category-map-successfull.webp" alt="category map successfull"></p><p>And after mapping the categories, the admin can view them in the list.</p><p><strong>Note:</strong></p><p>Only the manual collection of the Shopify store will be visible at the Magento end for mapping.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/collection.png" target="_blank" rel="noopener noreferrer"><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/collection.png" alt="collection"></a></p><h2 id="export-customers" tabindex="-1"><a class="header-anchor" href="#export-customers"><span><strong>Export Customers</strong></span></a></h2><p>You can easily migrate customers from Magento 2 to Shopify using the Shopify Connector module. Follow the steps below to export and map customers successfully.</p><p>In the Magento 2 admin panel, navigate to: <strong>Webkul Shopify Connector -&gt; Customers Export</strong></p><p>From here, you can view all Magento 2 customers available for export to Shopify.</p><h3 id="select-customers-for-export" tabindex="-1"><a class="header-anchor" href="#select-customers-for-export"><span>Select Customers for Export</span></a></h3><ul><li>Select the customers you want to export.</li><li>Use the checkbox option to choose multiple customers.</li><li>Click on the Export And Map Customers button.</li></ul><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/magetno2-customer-export-to-shopify-1.webp" alt="magetno2-customer-export-to-shopify"></p><h3 id="customer-export-execution" tabindex="-1"><a class="header-anchor" href="#customer-export-execution"><span>Customer Export Execution</span></a></h3><p>Once the export process starts, the execution page will display the export progress.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/magetno2-customer-export-to-shopify-page.webp" alt="magetno2-customer-export-to-shopify-page"></p><h3 id="verify-customers-in-shopify" tabindex="-1"><a class="header-anchor" href="#verify-customers-in-shopify"><span>Verify Customers in Shopify</span></a></h3><ul><li>Login to your Shopify admin panel.</li><li>Go to Customers.</li><li>Verify that the exported customers are available in Shopify.</li></ul><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/shopify-customer-view-page-1.webp" alt="shopify-customer-view-page"></p><h3 id="send-customer-reset-mail-for-shopify" tabindex="-1"><a class="header-anchor" href="#send-customer-reset-mail-for-shopify"><span>Send Customer Reset Mail for Shopify</span></a></h3><p>The Shopify Connector module also allows the admin to send Shopify customer account reset emails directly from Magento 2.</p><p>This feature helps customers activate or reset their Shopify account passwords after customer export.</p><p><strong>Navigate to:</strong> **Webkul Shopify Connector -&gt; Customers Export\xA0<br> **</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/magento2-customer-reset-mail.webp" alt="magento2-customer-reset-mail"></p><h3 id="select-customer-and-choose-reset-mail-action" tabindex="-1"><a class="header-anchor" href="#select-customer-and-choose-reset-mail-action"><span>Select Customer and Choose Reset Mail Action</span></a></h3><ul><li>Select the customer using the checkbox.</li><li>From the <strong>Actions</strong> dropdown, choose: <strong>Reset Mail for Shopify</strong></li><li>Click on the Submit button.</li></ul><p>This action will send a Shopify customer account reset email to the selected customer email address.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/magento2-customer-reset-mail-sent-1.webp" alt="magento2-customer-reset-mail-sent"></p><p>After the system completes the action successfully, it displays a confirmation message indicating that it has sent the reset email.</p><h2 id="import-product" tabindex="-1"><a class="header-anchor" href="#import-product"><span><strong>Import Product</strong></span></a></h2><p>The admin can import the desired products from the Shopify store to their Magento store.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/product-page-2.png" target="_blank" rel="noopener noreferrer"><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/product-page-2.png" alt="product page"></a></p><p>To import products from the Shopify store, the admin will click on the **Map Product\xA0**tab as per the image.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-map-product.webp" alt="map-product"></p><p>Here, the admin will:</p><ul><li>Import Product:\xA0when clicking on Import Product From Shopify, the temporary product data is created and stored in Magento 2 database.</li></ul><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-product-import.webp" alt="product import"></p><ul><li>Run Profile:\xA0It is used to create/add the imported products to Magento 2 store.</li></ul><p>Clicking the <strong>Run Profile</strong> tab will initiate the product creation <strong>.</strong></p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/profile.png" target="_blank" rel="noopener noreferrer"><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/profile.png" alt="profile"></a></p><ul><li>Import Product Image: It is used to import the product images from Shopify. Clicking on Import Product Image will initiate the image import.</li></ul><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-image-import-profiler.webp" alt="import image profiler"></p><p>After successful execution, the admin can check the imported products in the imported product list.</p><p>Also, by navigating to the Magento store category as per the category mapping is done for the imported product.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/front-end.png" target="_blank" rel="noopener noreferrer"><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/front-end.png" alt="front-end"></a></p><p>**Note:\xA0**</p><ul><li>If category mapping is not done for the Shopify product category, then the imported products will be assigned to the default category as per the configuration.</li><li>If the category mapping is done for the Shopify product category, then the imported products will not be assigned to the default category.</li><li>The imported products automatically get assigned to the mapped category only.</li></ul><h3 id="configurable-product" tabindex="-1"><a class="header-anchor" href="#configurable-product"><span>Configurable Product:</span></a></h3><p>Along with the simple product, the admin can even import the configurable product from the Shopify store.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/configurable-product.png" target="_blank" rel="noopener noreferrer"><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/configurable-product.png" alt="configurable product"></a></p><p>To import the configurable product successfully, simply follow the import process defined above for simple product import.</p><p>After the import, the configurable product will be created in the Magento 2 store as per the below image.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-import-configurable-product-1.webp" alt="import-configurable-product"></p><p>The admin can even check the imported configurable product at the front-end also.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/import-2.png" target="_blank" rel="noopener noreferrer"><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/import-2.png" alt="import"></a></p><h3 id="how-to-change-the-category-of-the-imported-products" tabindex="-1"><a class="header-anchor" href="#how-to-change-the-category-of-the-imported-products"><span>HOW TO CHANGE THE CATEGORY OF THE IMPORTED PRODUCTS?:</span></a></h3><p>The admin can\xA0change the category of imported products. For this, the admin will click on\xA0**Map Product\xA0**tab as per the image.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-change-category-1.webp" alt="change-category"></p><p>To change the category of the imported products, the admin will do the following:</p><ul><li>Select one or more than one product from the imported products list.</li><li>Select\xA0Assign to Category\xA0option from the\xA0Actions\xA0drop-down list. This will display the\xA0Category\xA0field and\xA0Submit\xA0button\xA0beside the\xA0Actions\xA0drop-down list.</li><li>Select the desired category from the\xA0Category\xA0drop-down list.</li><li>Proceed further by clicking on the\xA0Submit\xA0button.</li></ul><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-category-assigned-1.webp" alt="category-updated"></p><p>Also, the admin can check the newly assigned category of the product by navigating to the category which has been assigned to the product.</p><p>**NOTE:\xA0**</p><ul><li>The product information like base image, additional images, name, price, SKU, description, quantity, weight and super attributes with options get imported along with the product.</li><li>The module import simple and configurable product (product with variants) types.</li><li>If importing a product that has no weight then, at Magento end that product will have the default weight 1 after the import.</li></ul><h2 id="import-order" tabindex="-1"><a class="header-anchor" href="#import-order"><span><strong>Import Order</strong></span></a></h2><p>To import the orders from the Shopify store, the admin will click on **Import Order From Shopify\xA0**tab as per the image.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-map-order-1.webp" alt="map-order"></p><p>Here the admin will:</p><ul><li>Import Order From Shopify:\xA0when clicking on the “Import Order From Shopify” button, the temporary order data is created and stored in Magento 2 database.</li></ul><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/pop-up-4.png" target="_blank" rel="noopener noreferrer"><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/pop-up-4.png" alt="pop-up"></a></p><ul><li>Run Profiler:\xA0It is used to create/add the imported orders to Magento 2 store.</li></ul><p>Clicking the “Create Imported Order” tab will initiate the\xA0<strong>Run Profile.</strong></p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/run-profile-1.png" target="_blank" rel="noopener noreferrer"><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/run-profile-1.png" alt="profile"></a></p><p>After successful execution, the admin can check the imported orders in the imported order list.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-map-order-2.webp" alt="new-order-imported"></p><p>The admin can check the details of imported orders by navigating to the\xA0**Sales&gt;Orders.\xA0**</p><p><strong>Note –</strong></p><ul><li>A cron is set for this module for auto-synchronization of orders.</li><li>The admin has to configure the cron on Magento 2 server which will automatically import the orders from Shopify store to Magento 2 store after every one hour by default.</li><li>The admin can even change the default cron time.</li><li>If you are importing orders using cron and certain\xA0order items do not exist in Magento 2 store. Then, first those items get created automatically in your Magento 2 store.</li><li>But if you are importing orders manually then, those products should be imported first.</li><li>The admin will not get any Email notifications for any order placed on the Shopify store.</li><li>However, the admin needs to check those orders normally by navigating to\xA0Sales &gt; Orders\xA0after importing them.</li><li>If you are importing the Shopify order and that customer doesn’t exist in Magento 2.\xA0Then, while order import that Shopify customer gets created in\xA0 Magento 2 automatically.</li></ul><h2 id="export-product" tabindex="-1"><a class="header-anchor" href="#export-product"><span><strong>Export Product</strong></span></a></h2><p>The admin can export the desired products from the Magento store to their Shopify store.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/shopify-product-that-exported-e1634890281206.png" alt="shopify-product-that-exported"></p><p>To export products from the Magento store, the admin will click on the **Export Products To Shopify **tab as per the image.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-export-3.webp" alt="export"></p><p>To Export the products to the Shopify store, the admin will:</p><ul><li>Select the products which the admin wants to export to the Shopify store.</li><li>Then select the\xA0“Export to Shopify”\xA0option from the\xA0“Action”\xA0drop-down list.</li><li>Proceed further by clicking on the\xA0“Submit”\xA0button which gets visible when selects the “Export to Shopify”\xA0option from the\xA0“Action”\xA0drop-down list.</li><li>This will navigate\xA0the admin to the “Run Profile” page as per the image.</li></ul><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/profile-1.png" target="_blank" rel="noopener noreferrer"><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/profile-1.png" alt="profile"></a></p><p>Once the execution is completed, the admin can click\xA0the **“Back”\xA0**button to navigate back. Then, the admin will go to the Shopify account and navigates to the <strong>Selling</strong>\xA0page.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/exported-products-e1634890437911.png" alt="exported-products"></p><p><strong>Note:\xA0If category mapping is not done for the Shopify product category, then the products will not be exported.</strong></p><h3 id="configurable-product-1" tabindex="-1"><a class="header-anchor" href="#configurable-product-1"><span>Configurable Product:</span></a></h3><p>Along with the simple product, the admin can even export the configurable product from the Magento store.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/configurable-1.png" target="_blank" rel="noopener noreferrer"><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/configurable-1.png" alt="configurable"></a></p><p>To export the configurable product successfully, simply follow the export process defined above for simple product export.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/shopify.png" target="_blank" rel="noopener noreferrer"><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/shopify.png" alt="shopify"></a></p><p><strong>NOTE:</strong></p><ul><li>The system exports product information such as the base image, name, price, and quantity along with the product.</li><li>The admin can export the simple and configurable products from Magento store to the Shopify Store.</li><li>If exporting a product with no description then, at Shopify end that product will have its name as it’s description. Because at Shopify store, one cannot create the product without description.</li></ul><h2 id="export-orders-to-shopify" tabindex="-1"><a class="header-anchor" href="#export-orders-to-shopify"><span>Export Orders To Shopify</span></a></h2><p>The Webkul Shopify Connector allows the admin to export Magento 2 orders directly to Shopify in a few simple steps.</p><p>The connector supports exporting different order statuses such as: Complete, Processing, Closed, Pending, Refunded, And other Magento order statuses .</p><p>Go to the **Webkul Shopify Connector -&gt; ****Export Orders To Shopify: **Select the required orders.</p><ol><li>Choose Export To Shopify from the action dropdown.</li><li>Click Submit.</li></ol><p>After submitting, the selected orders are prepared for export to Shopify.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/magento2-order-export-to-shopify.webp" alt="magento2-order-export-to-shopify"></p><p>Once the orders are selected, the export profile starts running.</p><p>After the process is completed successfully, a confirmation message appears showing that the orders have been exported to Shopify.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/magento2-profiler-run-to-export-orders.webp" alt="magento2-profiler-run-to-export-orders"></p><h2 id="view-exported-orders-in-shopify" tabindex="-1"><a class="header-anchor" href="#view-exported-orders-in-shopify"><span>View Exported Orders in Shopify</span></a></h2><p>After the export process is completed, the orders become visible in the Shopify admin panel under the <strong>Orders</strong> section.</p><h2 id="" tabindex="-1"><a class="header-anchor" href="#"><span>\xA0</span></a></h2><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/shopify-order-list.webp" alt="shopify-order-list"></p><p>The orders are successfully synchronized from Magento 2 to Shopify and are ready for further processing in Shopify.</p><h2 id="templates" tabindex="-1"><a class="header-anchor" href="#templates"><span><strong>Templates</strong></span></a></h2><p>This module allows the admin to export the product’s additional information along with the product as per the choice.</p><p>For this, the admin needs to create the listing templates by navigating to <strong>Webkul Shopify Connector</strong>-&gt; <strong>Templates</strong>****as per the below image.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-sidepanel-6.webp" alt="webkul-magento2-shopify-connector-sidepanel"></p><p>Clicking on the “<strong>Templates”</strong>\xA0option will navigate the admin to the Shopify Listing Template page as per the below image.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-listing-templates.webp" alt="listing templates"></p><p>Here, the admin can:</p><ul><li>View the complete list of the templates.</li><li>Edit or delete the templates.</li><li>Add or create an unlimited number of templates.</li></ul><h3 id="create-template-shopify-template-listing" tabindex="-1"><a class="header-anchor" href="#create-template-shopify-template-listing"><span>Create Template: <strong>Shopify Template Listing</strong></span></a></h3><p>The admin will navigate to the <strong>Shopify Template Listing</strong>\xA0page when clicks on the <strong>Create Template</strong> button.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-create-template.webp" alt="create template"></p><p>Here, the admin will:</p><ul><li>Title-\xA0Enter the template name.</li><li>Template Content-\xA0Define the\xA0Template variables.</li><li>Status-\xA0Can enable or disable a template.</li><li>Map the Magento store product attributes to the configured template variables defined in the Template Content field.</li></ul><p><strong>Note:</strong>\xA0Each Variable should be unique within the same template.</p><p>When the product get export, the additional details will also get export to the Shopify store as per the below image.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/exported-products-e1634890437911.png" alt="exported-products"></p><p>And on the\xA0<strong>edit</strong>\xA0product page at <strong>Shopify</strong>, you can edit the <strong>Item Description</strong>\xA0section.</p><h2 id="price-rule-update-price-of-synced-products" tabindex="-1"><a class="header-anchor" href="#price-rule-update-price-of-synced-products"><span>**Price Rule: Update Price Of Synced Products\xA0**</span></a></h2><p>The admin can easily update the price of the synced products automatically.</p><p>For this, the admin needs to create the Price Rules by navigating to <strong>Webkul Shopify Connector –</strong>&gt; **Price Rule\xA0**as per the below image.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-sidepanel-7.webp" alt="menu-sidepanel"></p><p>After clicking on Price Rules option, the following page will open showing Price Rules list.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-price-rule.webp" alt="price rule"></p><p>Here, the admin can:</p><ul><li>Edit –\xA0edit the Price Rule details by clicking on this link.</li><li>Delete\xA0– remove the existing Price Rule from the list clicking Action\xA0drop-down.</li><li>Add Rule –\xA0add/create new Price Rule clicking Add Rule button.</li></ul><p>After clicking on “<strong>Add\xA0Rule</strong>“, the admin will navigate to the New price rule page as per the below image.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2018/10/webkul-magento2-shopify-connector-add-price-rule.webp" alt="add price rule"></p><p>Here, the admin will:</p><ul><li>Product Price\xA0From:\xA0select the minimum price for the\xA0price rule to be active from.</li><li>Product Price to:\xA0set the maximum price for the\xA0price rule to get inactive.</li><li>Operation Type:\xA0Select the operation type as fixed or percentage.</li><li>Operation:\xA0Select the operation as increase or decrease.</li><li>Price:\xA0enter the amount.</li><li>Shopify Store:\xA0select the store.</li><li>Status:\xA0enable/disable the price rule.</li></ul><p>**HOW WILL IT WORK?<br> **Suppose the price of the sync product is 100 and the admin has to configure –</p><ul><li>Operation Type:\xA0Percentage</li><li>Operation:\xA0Increase</li><li>Price:\xA010</li></ul><p>Then 10% of 100 will get add to the original price of the product ie; (10 % 100) + 100 = 10+100 = 110.</p><p>Else if\xA0the admin has configured –</p><ul><li>Operation Type:\xA0Fixed</li><li>Operation:\xA0Decrease</li><li>Price:\xA010</li></ul><p>Then the system decreases <strong>10</strong> from the original product price, resulting in <strong>90</strong> (100 − 10 = 90).</p><p>**Configuration: **Tapping on this sub-menu option will take you directly to the main configuration settings in the backend panek for the extension.</p><h3 id="get-in-touch" tabindex="-1"><a class="header-anchor" href="#get-in-touch"><span>Get in touch</span></a></h3><p>That’s all for the Shopify Connector for Magento 2 (Adobe Commerce) Module.</p><p>If you are having any queries or suggestions, feel free to mail us at <a href="/cdn-cgi/l/email-protection" target="_blank" rel="noopener noreferrer">[email\xA0protected]</a></p><p>Explore the\xA0<a href="https://webkul.com/adobe-commerce-cloud/" target="_blank" rel="noopener noreferrer">Adobe Commerce Cloud</a> development services by Webkul.</p><p>We also provide <a href="https://webkul.com/shopify-headless-development/" target="_blank" rel="noopener noreferrer">Shopify Hydrogen Development</a> services as well.</p><p>Current Product Version - 4.0.4</p><p>Supported Framework Version - Magento 2.0.x, 2.1.x, 2.2.x,2.3.x, 2.4.x</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/11/kajal-sharma-2.webp" alt="author-thumb"></p><p><a href="https://webkul.com/blog/author/kajalsharma-magento920/" target="_blank" rel="noopener noreferrer">Kajal Sharma 7 Badges</a></p><ul><li>9 Jun, 2026 Updated by - Lucky Yadav</li><li>14 May, 2026 Updated by - Gourav Sonaniya</li></ul><p>View More</p>`,328)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};